──────,// module-info.java (in src/main/java):,\n\n// module com.myapp.core {,//     // Dependencies,//     requires java.sql;,//     requires java.net.http;,//     requires com.fasterxml.jackson.databind;,//     requires transitive com.myapp.shared; // propagate to dependents,//,//     // Exported packages (public API),//     exports com.myapp.core.api;,//     exports com.myapp.core.model;,//,//     // Internal packages NOT exported (strong encapsulation),//     // com.myapp.core.internal — hidden from other modules,//,//     // Open for reflection (needed for frameworks),//     opens com.myapp.core.model to com.fasterxml.jackson.databind;,//,//     // Service provider,//     provides com.myapp.spi.Plugin with com.myapp.core.DefaultPlugin;,//     uses com.myapp.spi.Plugin;,// }"
